bugs.patch:
Wrap in try/catch:
async function apiAuth(url, options = {}) {
    try {
        const res = await fetch(url, { ... });
        if (!res.ok) { throw new Error(`HTTP ${res.status}`); }
        return await res.json();
    } catch (err) {
        showToast('Erro de conexão. Verifique sua internet.', 'error');
        throw err;
    }
}

